import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const screening = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "find_moderate_probability_bets",
    args: {
      category: "all",
      minPrice: 0.4,
      maxPrice: 0.6,
      minLiquidity: 1000000,
      limit: 15,
      sortBy: "liquidity"
    }
  });

  const opportunities = Array.isArray(screening?.opportunities) ? screening.opportunities : [];
  if (!opportunities.length) {
    return {
      screeningSummary: screening?.summary || null,
      note: "No live contracts matched the 40%–60% price band with at least $1M liquidity."
    };
  }

  const shortlist = opportunities.slice(0, 5);
  const analyses = [];

  for (const opp of shortlist) {
    const id = opp.conditionId || opp.slug;
    if (!id) continue;

    const liq = await callMcpSkill({
      toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
      toolName: "analyze_market_liquidity",
      args: opp.conditionId
        ? { conditionId: opp.conditionId }
        : opp.slug
          ? { slug: opp.slug }
          : { marketQuery: opp.market }
    });

    const spread =
      typeof liq?.spread?.spreadCents === "number"
        ? liq.spread.spreadCents
        : typeof liq?.spread?.absolute === "number"
          ? liq.spread.absolute * 100
          : null;

    const sell5k =
      liq?.whaleCost?.sell5k && typeof liq.whaleCost.sell5k === "object"
        ? liq.whaleCost.sell5k
        : null;

    const depth = liq?.depth?.totalDepthUsd ?? liq?.depth?.askDepthUsd ?? null;

    const scoreParts = [];
    if (typeof spread === "number") scoreParts.push(Math.max(0, 10 - spread * 100));
    if (typeof depth === "number") scoreParts.push(Math.min(10, depth / 1000000));
    if (typeof opp.liquidity === "number") scoreParts.push(Math.min(10, opp.liquidity / 1000000));

    const tradabilityScore =
      scoreParts.length > 0
        ? scoreParts.reduce((a, b) => a + b, 0) / scoreParts.length
        : null;

    analyses.push({
      market: opp.market,
      url: opp.url,
      slug: opp.slug,
      conditionId: opp.conditionId,
      currentPrice: opp.currentPrice,
      liquidity: opp.liquidity,
      volume24h: opp.volume24h,
      spreadCents: spread,
      liquidityScore: liq?.liquidityScore ?? null,
      depthUsd: depth,
      sell5k: sell5k,
      whaleCost: liq?.whaleCost ?? null,
      recommendation: liq?.recommendation ?? null,
      tradabilityScore
    });
  }

  analyses.sort((a, b) => {
    const aScore = a.tradabilityScore ?? -1;
    const bScore = b.tradabilityScore ?? -1;
    return bScore - aScore;
  });

  return {
    screeningSummary: screening.summary,
    screenedCount: opportunities.length,
    shortlistCount: shortlist.length,
    rankedTradableMarkets: analyses
  };
}

