  const topMarkets = Array.isArray(topMarketsResult?.markets) ? topMarketsResult.markets : [];
  const trendingMarkets = Array.isArray(trendingResult?.trendingMarkets) ? trendingResult.trendingMarkets : [];

  const candidatePool = [...topMarkets, ...trendingMarkets].filter((m) => m && (m.title || m.slug));
  const rankedCandidates = pickTopSemanticCandidates({
    target: "most liquid live multi-outcome politics event",
    candidates: candidatePool,
    requiredTerms: ["politics"],
    avoidTerms: ["single", "yes/no", "binary"],
    limit: 5
  });

  const chosenMarket = rankedCandidates[0] || null;
  if (!chosenMarket) {
    return {
      missingData: ["No suitable live politics market candidates were found."],
      attemptedBranches: ["get_top_markets(category=politics, sortBy=liquidity)", "discover_trending_markets(category=politics)"],
      stopReason: "empty_candidate_pool",
      initialBatchTelemetry: initialBatch.summary
    };
  }

  const eventQuery = chosenMarket.title || chosenMarket.slug;
