      slug: eventSlug || undefined,
      query: eventTitle,
      outcomes: outcomeNames.length > 0 ? outcomeNames : undefined,
      limit: 4,
      sortBy: "volume"
    }
  });

  const analyzedOutcomes = Array.isArray(liquidityAnalysis?.analyzedOutcomes)
    ? liquidityAnalysis.analyzedOutcomes
    : [];

  const analyzedByName = new Map();
  for (const row of analyzedOutcomes) {
    if (row && row.matchedName) analyzedByName.set(row.matchedName, row);
  }

  const rows = topFourOutcomes.map((o) => {
    const a = analyzedByName.get(o.name) || {};
    return {
      outcome: o.name,
      price: o.price,
