    const efficiency = byKey[`efficiency-${index}`] || null;

    const marketTitle = market?.title || market?.market || "";
    const currentPrice = typeof market?.currentPrice === "number" ? market.currentPrice : null;
    const liquidity = typeof market?.liquidity === "number" ? market.liquidity : null;

    const vig = efficiency?.marketEfficiency?.vig;
    const isEfficient = efficiency?.marketEfficiency?.isEfficient;
    const spreadBps = Array.isArray(efficiency?.outcomes) && efficiency.outcomes.length > 0
      ? Math.max(...efficiency.outcomes.map((o) => (typeof o?.price === "number" ? o.price : 0))) - Math.min(...efficiency.outcomes.map((o) => (typeof o?.price === "number" ? o.price : 0)))
      : null;

    const edgeAfterCosts =
      typeof vig === "number" && typeof spreadBps === "number"
        ? (1 - vig) - (spreadBps / 100)
        : null;

    return {
      rank: index + 1,
      title: marketTitle,
      slug: market?.slug || null,
      url: market?.url || null,
      conditionId: market?.conditionId || null,
      liquidity,
      currentPrice,
      rules: rules && !rules.error ? rules : { error: rules?.error || "rule_validation_unavailable" },
      efficiency: efficiency && !efficiency.error ? efficiency : { error: efficiency?.error || "efficiency_check_unavailable" },
      edgeAfterCosts,
      executableAfterCosts: typeof edgeAfterCosts === "number" ? edgeAfterCosts > 0 && isEfficient !== false : null
    };
  });

  const actionable = finalSetups.filter((s) => s.executableAfterCosts === true);

  return {
    workflowSummary: {
      stage: "discovery_shortlist_validate_rank",
      liveMarketsFound: markets.length,
      liquidMarketsFound: liquidMarkets.length,
      shortlistedCount: shortlistedMarkets.length,
      validatedCount: finalSetups.length,
      actionableCount: actionable.length
    },
    topSetups: finalSetups,
    actionableSetups: actionable,
    parallelTelemetry: validationBatch.summary,
    fetchedAt: discovery?.fetchedAt || null
  };
}

