      tradeLimit: 20
    }
  });

  const recentTrades = Array.isArray(result?.recentTrades) ? result.recentTrades : [];
  const tradesSummary = result?.tradesSummary || {};
  const selectedMarket = result?.selectedMarket || {};
  const openInterest = result?.openInterest || {};
  const noResultsReason = result?.noResultsReason;

  const totalVolume = typeof tradesSummary.totalVolume === "number" ? tradesSummary.totalVolume : null;
  const totalTrades = typeof tradesSummary.totalTrades === "number" ? tradesSummary.totalTrades : null;
  const buyVolume = typeof tradesSummary.buyVolume === "number" ? tradesSummary.buyVolume : null;
  const sellVolume = typeof tradesSummary.sellVolume === "number" ? tradesSummary.sellVolume : null;
  const avgPrice = typeof tradesSummary.avgPrice === "number" ? tradesSummary.avgPrice : null;
  const oiValue = typeof openInterest.value === "number" ? openInterest.value : null;

  let interpretation = "noise";
  let reasoning = [];

  if (totalTrades !== null && totalVolume !== null && oiValue !== null) {
    if (totalTrades >= 10 && totalVolume >= 5000 && oiValue >= 50000) {
      interpretation = "genuine conviction";
      reasoning.push("meaningful trade count");
      reasoning.push("healthy volume");
      reasoning.push("material open interest");
    } else if (totalTrades >= 5 && totalVolume >= 2000 && oiValue >= 20000) {
      interpretation = "likely some conviction, but mixed with noise";
      reasoning.push("some sustained activity");
      reasoning.push("open interest is non-trivial");
    } else {
      interpretation = "mostly noise";
      reasoning.push("limited trade activity");
      reasoning.push("low or thin open interest");
    }
  }

  if (typeof buyVolume === "number" && typeof sellVolume === "number") {
    const imbalance = Math.abs(buyVolume - sellVolume);
    const total = buyVolume + sellVolume;
    if (total > 0 && imbalance / total > 0.25) {
      reasoning.push("directional imbalance in tape");
    } else if (total > 0) {
      reasoning.push("two-sided flow looks balanced");
    }
  }

  return {
    market: {
      title: selectedMarket.title || null,
      conditionId: selectedMarket.conditionId || null,
      url: selectedMarket.url || null,
      endDate: selectedMarket.endDate || null,
      category: selectedMarket.category || null,
      liquidity: typeof selectedMarket.liquidity === "number" ? selectedMarket.liquidity : null,
      volume24h: typeof selectedMarket.volume24h === "number" ? selectedMarket.volume24h : null,
      selectionReason: selectedMarket.selectionReason || null
    },
    activity: {
      totalTrades,
      totalVolume,
      buyVolume,
      sellVolume,
      avgPrice,
      openInterest: oiValue
    },
    recentTradesSample: recentTrades.slice(0, 10),
    read: {
      interpretation,
      reasoning
    },
    noResultsReason: noResultsReason || null,
    fetchedAt: result?.fetchedAt || null
  };
}

