      filter: {
        category: "politics",
        minLiquidity: 10000,
        probabilityFloor: 0.65
      }
    },
    rankedMarkets: scored.slice(0, 10),
    note: scored.length
      ? "Ranked by a practical cleanliness score using liquidity, 24h volume, and distance from 50/50. This is a proxy for easier execution and lower day-to-day noise."
