import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const probe = await callMcpSkill({
    toolId,
    toolName: "get_top_markets",
    args: {
      limit: 50,
      sortBy: "liquidity",
      category: "politics",
      minLiquidity: 10000,
      includeNearResolved: false
    }
  });

  const allMarkets = Array.isArray(probe?.markets) ? probe.markets : [];

  const probabilityMatches = allMarkets.filter((m) => {
    const p = typeof m?.currentPrice === "number" ? m.currentPrice : null;
    return p !== null && p >= 0.4 && p <= 0.75;
  });

  const highProbabilityMatches = allMarkets.filter((m) => {
    const p = typeof m?.currentPrice === "number" ? m.currentPrice : null;
    return p !== null && p >= 0.65;
  });

  const candidates = (probabilityMatches.length ? probabilityMatches : allMarkets).slice(0, 10);

  const analyzed = [];
  for (const m of candidates) {
    const liquidityAnalysis = await callMcpSkill({
      toolId,
      toolName: "analyze_market_liquidity",
      args: {
        conditionId: m.conditionId
      }
    });

    const efficiencyAnalysis = await callMcpSkill({
      toolId,
      toolName: "check_market_efficiency",
      args: {
        conditionId: m.conditionId
      }
    });

    const price = typeof m.currentPrice === "number" ? m.currentPrice : 0;
    const liquidity = typeof m.liquidity === "number" ? m.liquidity : 0;
    const volume24h = typeof m.volume24h === "number" ? m.volume24h : 0;

    const spreadBps =
      typeof liquidityAnalysis?.spread?.bps === "number"
        ? liquidityAnalysis.spread.bps
        : typeof liquidityAnalysis?.spread?.spreadBps === "number"
          ? liquidityAnalysis.spread.spreadBps
          : null;

    const whaleCost5000 =
      typeof liquidityAnalysis?.whaleCost?.buy5000 === "number"
        ? liquidityAnalysis.whaleCost.buy5000
        : typeof liquidityAnalysis?.whaleCost?.sell5000 === "number"
          ? liquidityAnalysis.whaleCost.sell5000
          : null;

    const vig =
      typeof efficiencyAnalysis?.marketEfficiency?.vig === "number"
        ? efficiencyAnalysis.marketEfficiency.vig
        : null;

    const spreadPenalty = spreadBps !== null ? Math.min(spreadBps, 200) * 50 : 5000;
    const vigPenalty = vig !== null ? vig * 100000 : 5000;
    const cleanlinessScore =
      liquidity * 0.6 +
      volume24h * 0.25 +
      Math.abs(price - 0.5) * 100000 * 0.15 -
      spreadPenalty -
      vigPenalty;

    analyzed.push({
      title: m.title,
      url: m.url,
      slug: m.slug,
      conditionId: m.conditionId,
      currentPrice: price,
      liquidity,
      volume24h,
      endDate: m.endDate,
      spreadBps,
      whaleCost5000,
      vig,
      marketEfficiency:
        efficiencyAnalysis?.marketEfficiency || null,
      liquidityAnalysis,
      efficiencyAnalysis,
      cleanlinessScore
    });
  }

  analyzed.sort((a, b) => {
    if (b.cleanlinessScore !== a.cleanlinessScore) return b.cleanlinessScore - a.cleanlinessScore;
    if (b.liquidity !== a.liquidity) return b.liquidity - a.liquidity;
    return b.currentPrice - a.currentPrice;
  });

  return {
    fetchedAt: probe?.fetchedAt,
    sourceNote: "Parsed from raw tool output using the actual response structure: result.markets[]",
    summary: {
      liveMarketsScanned: allMarkets.length,
      moderateProbabilityMatches: probabilityMatches.length,
      highProbabilityMatches: highProbabilityMatches.length,
      analyzedCandidates: analyzed.length,
      filter: {
        category: "politics",
        minLiquidity: 10000,
        probabilityFloor: 0.65,
        probeRange: "0.40-0.75"
      }
    },
    rankedMarkets: analyzed.slice(0, 10).map((m) => ({
      title: m.title,
      url: m.url,
      slug: m.slug,
      conditionId: m.conditionId,
      currentPrice: m.currentPrice,
      liquidity: m.liquidity,
      volume24h: m.volume24h,
      endDate: m.endDate,
      spreadBps: m.spreadBps,
      whaleCost5000: m.whaleCost5000,
      vig: m.vig,
      cleanlinessScore: m.cleanlinessScore
    })),
    note: analyzed.length
      ? "Ranked by a practical cleanliness score using liquidity, 24h volume, spread/vig, and distance from 50/50. WhaleCost/slippage was checked for a $5,000 position on each candidate."
      : "No politics markets met the probe filter, so no liquidity/slippage ranking could be produced.",
    gaps: {
      noHighProbabilityPoliticsMarketsFound: highProbabilityMatches.length === 0,
      noModerateProbabilityPoliticsMarketsFound: probabilityMatches.length === 0,
      liquidityVerificationPerformedOnCandidates: analyzed.length > 0,
      ifEmptyReason:
        analyzed.length === 0
          ? "The initial high-probability filter was too restrictive for the available politics markets; the returned dataset only exposed low-probability markets."
          : null
    }
  };
}

